use std::collections::HashMap;

struct PeripheralReading {
    transaction_id: u32,
    status_flags: u8,
    voltage_mv: i16,
    gpio_state: bool,
}

fn format_diagnostic_readout(readings: Vec<PeripheralReading>) -> String {
    let mut output = String::new();
    output.push_str("Diagnostic Bus Readout:n");
    output.push_str("--------------------------------------------------------n");

    for reading in readings {
        let id_str = format!("{:08X}", reading.transaction_id);
        let status_str = format!("0x{:02X}", reading.status_flags);
        let voltage_str = format!("{:5}mV", reading.voltage_mv);
        let gpio_str = if reading.gpio_state { "HIGH" } else { "LOW" };

        output.push_str(&format!( "{: <10} | {: <8} | {: <10} | {: <5} | {}", 
            id_str, status_str, voltage_str, gpio_str, "")
        );
        output.push_str("n");
    }
    output.push_str("--------------------------------------------------------n");
    output
}

fn main() {
    let readings = vec![
        PeripheralReading { transaction_id: 0xDEADBEEF, status_flags: 0xAA, voltage_mv: 1250, gpio_state: true },
        PeripheralReading { transaction_id: 0xCAFEBABE, status_flags: 0x01, voltage_mv: -50, gpio_state: false },
        PeripheralReading { transaction_id: 0xFEEDFACE, status_flags: 0xFF, voltage_mv: 3300, gpio_state: true },
    ];

    let result = format_diagnostic_readout(readings);
    println!("{}", result);
}

use std::collections::VecDeque;

#[derive(Debug, Clone)]
struct NetworkPacket {
    sequence_number: u32,
    source_id: u64,
    payload_size: usize,
}

fn process_upload_stream() -> Vec<NetworkPacket> {
    let mut buffer: VecDeque<NetworkPacket> = VecDeque::new();
    let initial_records = vec![
        NetworkPacket { sequence_number: 100, source_id: 0xDEADBEEF, payload_size: 256 },
        NetworkPacket { sequence_number: 101, source_id: 0xCAFEBABE, payload_size: 512 },
        NetworkPacket { sequence_number: 102, source_id: 0xDEADBEEF, payload_size: 128 },
    ];

    for record in initial_records.into_iter() {
        buffer.push_back(record);
    }

    let mut processed_packets = Vec::new();
    while let Some(packet) = buffer.pop_front() {
        if packet.payload_size > 100 {
            processed_packets.push(packet);
        } else {
            println!("Skipping small record: {}", packet.sequence_number);
        }
    }

    processed_packets
}

use std::collections::HashMap;
use std::error::Error;

struct Record {
    id: u64,
    name: String,
    value: f32,
}

fn process_records(data: Vec<Record>) -> Result<HashMap<String, Vec<(u64, f32)>>, Box<dyn Error>> {
    let mut results = HashMap::new();
    for record in data.into_iter() {
        let key = format!("{}", record.name);
        let entry = (record.id, record.value);
        results.entry(key).or_insert(Vec::new()).push(entry);
    }
    Ok(results)
}

fn main() -> Result<(), Box<dyn Error>> {
    let raw_data = vec![ 
        Record { id: 101, name: String::from("user_a"), value: 0.85 },
        Record { id: 102, name: String::from("user_b"), value: 0.12 },
        Record { id: 103, name: String::from("user_a"), value: 0.91 },
    ];

    match process_records(raw_data) {
        Ok(table) => {
            for (name, records) in table.iter() {
                println!("n--- {} ---", name);
                for &(id, val) in records.iter() {
                    println!("ID: {}, Value: {:.2}", id, val);
                }
            }
        },
        Err(e) => {
            eprintln!("Failed to process data: {}", e);
        }
    }
    Ok(())
}

