}

fn main() -> io::Result<()>{
    let records = vec![
        Record { sender: "server@local.com".to_string(), recipient: "userA@target.net".to_string(), subject: "Report Q3".to_string(), status_code: 250 },
        Record {
            sender: "server@local.com".to_string(),
            recipient: "userB@target.org".to_string(),
            subject: "Performance Metrics".to_string(),
            status_code: 354,
        },
        Record {
            sender: "server@local.com".to_string(),
            recipient: "unknown@fail.com".to_string(),
            subject: "Connection Test".to_string(),
            status_code: 500,
        },
    ];

    let mut output = String::new();
    output.push_str("Sender      | Recipient       | Subject              | Statusn");
    output.push_str("--------------|-----------------|----------------------|--------n");

    for record in records {
        output.push_str(&format!("{: <12} | {: <17} | {: <20} | {}n", 
