use std::io::{self, Write};

struct ProcessStat {
    name: String,
    cpu_usage: f64,
    memory_mb: u64,
}

fn print_process_table(stats: &[ProcessStat]) -> io::Result<()>{
    let mut stdout = io::stdout();
    writeln!(stdout, "=====================================================")?;
    writeln!(stdout, " Process Monitor Status")?;
    writeln!(stdout, "=====================================================")?;
    writeln!(stdout, " Name           | CPU % | Memory (MB)")?;
    writeln!(stdout, "-----------------------------------------------------")?;

    for stat in stats {
        writeln!(stdout, " {:<17} | {:<5.2} | {:<10}", 
            &stat.name,
            stat.cpu_usage,
            stat.memory_mb
        )?;
    }

    Ok(())
}

fn main() -> io::Result<()> {
    let initial_stats = vec![
        ProcessStat { name: "System Core".to_string(), cpu_usage: 12.5, memory_mb: 4096 },
        ProcessStat { name: "Game Engine".to_string(), cpu_usage: 35.1, memory_mb: 8192 },
        ProcessStat { name: "Overlay Script".to_string(), cpu_usage: 0.8, memory_mb: 128 },
    ];

    print_process_table(&initial_stats)?;

    write!(io::stdout(), "nPress Enter to exit...")?;
    io::stdout().flush()?;
    let mut buffer = String::new();
    io::stdin().read_line(&mut buffer)?; 

    Ok(())
}
